args.sparql:
SELECT (MAX(?attendance) AS ?maxAttendance)
WHERE {
  ?series wdt:P31 wd:Q530605 ;
          wdt:P585 ?eventDate .
  FILTER (STR(?eventDate) >= "1970-01-01" && STR(?eventDate) < "1980-01-01")

  ?game wdt:P1222 ?series .
  {
    ?game wdt:P1242 wd:Q16611 ; wdt:P1243 wd:Q17043 .
  } UNION {
    ?game wdt:P1242 wd:Q17043 ; wdt:P1243 wd:Q16611 .
  }
  ?game wdt:P1135 ?attendance .
}

SELECT (MAX(?attendance) AS ?maxAttendance)
WHERE {
  ?series wdt:P31 wd:Q530605 ;
          wdt:P585 ?eventDate ;
          wdt:P1231 wd:Q16611 ;
          wdt:P1231 wd:Q17043 .
  FILTER (STR(?eventDate) >= "1970-01-01" && STR(?eventDate) < "1980-01-01")

  ?game wdt:P1222 ?series .
  ?game wdt:P1135 ?attendance .
}
